decimal sumFemaleCulls = 0;
decimal sumFemaleCullsKill = 0;
decimal sumFemaleSample = 0;
decimal sumFemaleSexError = 0;
decimal sumFemaleTrans = 0;
decimal sumFemaleMort = 0;
decimal sumMaleCulls = 0;
decimal sumMaleCullsKill = 0;
decimal sumMaleSample = 0;
decimal sumMaleSexError = 0;
decimal sumMaleTrans = 0;
decimal sumMaleMort = 0;

private void xrTableCell20_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;

    // Get WC_LiveFemale value
    decimal wcLiveFemale = Convert.ToDecimal(GetCurrentColumnValue("WC_LiveFemale") ?? 0);

    // Calculate total FemaleDepl from separate sums
    decimal totalFemaleDepl = sumFemaleCulls + sumFemaleCullsKill + sumFemaleSample + 
                             sumFemaleSexError + sumFemaleTrans + sumFemaleMort;

    // Calculate denominator: WC_LiveFemale + totalFemaleDepl
    decimal denominator = wcLiveFemale + totalFemaleDepl;

    // Calculate percentage if denominator > 0
    if (denominator > 0) {
        decimal result = (totalFemaleDepl * 100) / denominator;
        cell.Text = result.ToString("N2"); // 1 decimal place
    } else {
        cell.Text = "0.00";
    }
}

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      // Sum each field separately for current row
    sumFemaleCulls += Convert.ToDecimal(GetCurrentColumnValue("Female_Culls") ?? 0);
    sumFemaleCullsKill += Convert.ToDecimal(GetCurrentColumnValue("Female_CullsKill") ?? 0);
    sumFemaleSample += Convert.ToDecimal(GetCurrentColumnValue("Female_Sample") ?? 0);
    sumFemaleSexError += Convert.ToDecimal(GetCurrentColumnValue("Female_SexError") ?? 0);
    sumFemaleTrans += Convert.ToDecimal(GetCurrentColumnValue("Female_Trans") ?? 0);
    sumFemaleMort += Convert.ToDecimal(GetCurrentColumnValue("FemaleMort") ?? 0);

     // Sum each MALE field separately for current row
    sumMaleCulls += Convert.ToDecimal(GetCurrentColumnValue("Male_Culls") ?? 0);
    sumMaleCullsKill += Convert.ToDecimal(GetCurrentColumnValue("Male_CullsKill") ?? 0);
    sumMaleSample += Convert.ToDecimal(GetCurrentColumnValue("Male_Sample") ?? 0);
    sumMaleSexError += Convert.ToDecimal(GetCurrentColumnValue("Male_SexError") ?? 0);
    sumMaleTrans += Convert.ToDecimal(GetCurrentColumnValue("Male_Trans") ?? 0);
    sumMaleMort += Convert.ToDecimal(GetCurrentColumnValue("MaleMort") ?? 0);
}

