private void xrTableCell84_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        XRTableCell cell = sender as XRTableCell;
      decimal totalFemaleDepl = sumFemaleCulls + sumFemaleCullsKill + sumFemaleSample + 
                             sumFemaleSexError + sumFemaleTrans + sumFemaleMort;

    // Get values from fields
    decimal wcLiveFemale = Convert.ToDecimal(GetCurrentColumnValue("WC_LiveFemale") ?? 0);
    decimal femaleFeed = Convert.ToDecimal(GetCurrentColumnValue("FemaleFeed") ?? 0);
     if (wcLiveFemale > 0) {
        // Method 1: As per your formula order
        decimal result = femaleFeed * 1000 / (wcLiveFemale + totalFemaleDepl )  / 7;

        // Method 2: More efficient
        // decimal result = (maleFeed * 1000) / (wcLiveMale * 7);

        cell.Text = result.ToString("N0");
    } else {
        cell.Text = "0";
    }


    }

private void xrTableCell85_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;
    decimal tota1MaleDepl = sumMaleCulls + sumMaleCullsKill + sumMaleSample + 
                           sumMaleSexError + sumMaleTrans + sumMaleMort;
    decimal wcLiveMale = Convert.ToDecimal(GetCurrentColumnValue("WC_LiveMale") ?? 0);
    decimal maleFeed = Convert.ToDecimal(GetCurrentColumnValue("MaleFeed") ?? 0);

    if (wcLiveMale > 0) {
        // Method 1: As per your formula order
        decimal result = maleFeed * 1000 / (wcLiveMale + tota1MaleDepl )  / 7;

        // Method 2: More efficient
        // decimal result = (maleFeed * 1000) / (wcLiveMale * 7);

        cell.Text = result.ToString("N0");
    } else {
        cell.Text = "0";
    }
}

private void xrTableCell86_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
         XRTableCell cell = sender as XRTableCell;
     decimal wcLiveFemale = Convert.ToDecimal(GetCurrentColumnValue("WC_LiveFemale") ?? 0);
    decimal wcLiveMale = Convert.ToDecimal(GetCurrentColumnValue("WC_LiveMale") ?? 0);
     decimal rowRatio = 0;
    if (wcLiveFemale > 0) 
        rowRatio = (wcLiveMale * 100) / wcLiveFemale;
    cell.Text = rowRatio.ToString("N1");

   }

private void xrTableCell68_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       XRTableCell cell = sender as XRTableCell;

    // Get values from fields
    decimal startFemaleBirds = Convert.ToDecimal(GetCurrentColumnValue("StartFemaleBirds") ?? 0);
    decimal startMaleBirds = Convert.ToDecimal(GetCurrentColumnValue("StartMaleBirds") ?? 0);

    // Calculate: (StartMaleBirds × 100) / StartFemaleBirds
    if (startFemaleBirds > 0) {
        decimal result = (startMaleBirds * 100) / startFemaleBirds;
        cell.Text = result.ToString("N2"); // 1 decimal place with %
        // Or without %: result.ToString("F1")
    } else {
        cell.Text = "0.00"; // or "0"
    } 
}
